        { id: 'lq888', type: 'dialogue', difficulty: 'hard', title: '在火车站', meaning: 'At the Train Station', turns: [{speaker:'A',chinese:'你好，我要一张去上海的车票。',pinyin:'nǐ hǎo, wǒ yào yì zhāng qù Shànghǎi de chēpiào.',meaning:'Hello, I want a train ticket to Shanghai.'},{speaker:'B',chinese:'要什么时候的？',pinyin:'yào shénme shíhou de?',meaning:'For when?'},{speaker:'A',chinese:'明天上午的，有没有高铁？',pinyin:'míngtiān shàngwǔ de, yǒu méiyǒu gāotiě?',meaning:'Tomorrow morning. Is there a high-speed train?'},{speaker:'B',chinese:'有，八点有一趟。二等座三百五十块。',pinyin:'yǒu, bā diǎn yǒu yí tàng. èr děng zuò sānbǎi wǔshí kuài.',meaning:'Yes, one at 8 AM. Second class is 350 yuan.'},{speaker:'A',chinese:'好的，就这个吧。',pinyin:'hǎo de, jiù zhège ba.',meaning:'OK, I’ll take this one.'}], questions: [{question:'Where is the person going?',options:['Beijing','Shanghai','Guangzhou','Hangzhou'],correct:1},{question:'What type of train?',options:['Regular','High-speed','Sleeper','Subway'],correct:1}] },
        { id: 'lq889', type: 'dialogue', difficulty: 'hard', title: '在邮局', meaning: 'At the Post Office', turns: [{speaker:'A',chinese:'你好，我要寄一个包裹到北京。',pinyin:'nǐ hǎo, wǒ yào jì yí gè bāoguǒ dào Běijīng.',meaning:'Hello, I want to mail a package to Beijing.'},{speaker:'B',chinese:'里面是什么？',pinyin:'lǐmiàn shì shénme?',meaning:'What is inside?'},{speaker:'A',chinese:'一些书和衣服。',pinyin:'yìxiē shū hé yīfu.',meaning:'Some books and clothes.'},{speaker:'B',chinese:'请填一下这个单子。',pinyin:'qǐng tián yíxià zhège dānzi.',meaning:'Please fill out this form.'},{speaker:'A',chinese:'大概几天能到？',pinyin:'dàgài jǐ tiān néng dào?',meaning:'About how many days to arrive?'},{speaker:'B',chinese:'大概三到五天吧。',pinyin:'dàgài sān dào wǔ tiān ba.',meaning:'About 3 to 5 days.'}], questions: [{question:'What is being mailed?',options:['A letter','A package','Money','Documents'],correct:1},{question:'How long for delivery?',options:['1-2 days','3-5 days','1 week','2 weeks'],correct:1}] },
        { id: 'lq890', type: 'dialogue', difficulty: 'hard', title: '在宾馆', meaning: 'At a Hotel', turns: [{speaker:'A',chinese:'你好，我想订一个房间。',pinyin:'nǐ hǎo, wǒ xiǎng dìng yí gè fángjiān.',meaning:'Hello, I want to book a room.'},{speaker:'B',chinese:'单人间还是标准间？',pinyin:'dānrénjiān háishì biāozhǔnjiān?',meaning:'Single room or standard room?'},{speaker:'A',chinese:'单人间就行。一晚多少钱？',pinyin:'dānrénjiān jiù xíng. yì wǎn duōshao qián?',meaning:'Single room is fine. How much per night?'},{speaker:'B',chinese:'三百块一晚，含早餐。',pinyin:'sānbǎi kuài yì wǎn, hán zǎocān.',meaning:'300 yuan per night, includes breakfast.'},{speaker:'A',chinese:'好的，我住两晚。',pinyin:'hǎo de, wǒ zhù liǎng wǎn.',meaning:'OK, I’ll stay two nights.'}], questions: [{question:'What type of room was chosen?',options:['Double','Single','Suite','Standard'],correct:1},{question:'Does the price include breakfast?',options:['No','Yes','Depends','Not mentioned'],correct:1}] },
        { id: 'lq891', type: 'dialogue', difficulty: 'hard', title: '打招呼', meaning: 'Greetings', turns: [{speaker:'A',chinese:'你好！你叫什么名字？',pinyin:'nǐ hǎo! nǐ jiào shénme míngzi?',meaning:'Hello! What is your name?'},{speaker:'B',chinese:'我叫小王。你呢？',pinyin:'wǒ jiào Xiǎo Wáng. nǐ ne?',meaning:'My name is Xiao Wang. And you?'},{speaker:'A',chinese:'我叫小李。很高兴认识你。',pinyin:'wǒ jiào Xiǎo Lǐ. hěn gāoxìng rènshi nǐ.',meaning:'My name is Xiao Li. Nice to meet you.'},{speaker:'B',chinese:'我也很高兴认识你！',pinyin:'wǒ yě hěn gāoxìng rènshi nǐ!',meaning:'Nice to meet you too!'}], questions: [{question:'What is B’s name?',options:['Xiao Li','Xiao Wang','Xiao Zhang','Xiao Zhao'],correct:1}] },
        { id: 'lq892', type: 'dialogue', difficulty: 'hard', title: '在餐厅吃饭', meaning: 'Eating at a Restaurant', turns: [{speaker:'A',chinese:'你好，几位？',pinyin:'nǐ hǎo, jǐ wèi?',meaning:'Hello, how many people?'},{speaker:'B',chinese:'两位。有没有靠窗的位置？',pinyin:'liǎng wèi. yǒu méiyǒu kào chuāng de wèizhì?',meaning:'Two. Do you have a window seat?'},{speaker:'A',chinese:'有的，请跟我来。',pinyin:'yǒu de, qǐng gēn wǒ lái.',meaning:'Yes, please follow me.'},{speaker:'B',chinese:'请把菜单给我看看。',pinyin:'qǐng bǎ càidān gěi wǒ kàn kàn.',meaning:'Please show me the menu.'},{speaker:'A',chinese:'好的，这是菜单。您想喝点什么？',pinyin:'hǎo de, zhè shì càidān. nín xiǎng hē diǎn shénme?',meaning:'OK, here’s the menu. What would you like to drink?'},{speaker:'B',chinese:'先来一壶茶吧。',pinyin:'xiān lái yì hú chá ba.',meaning:'A pot of tea first please.'}], questions: [{question:'Where do they want to sit?',options:['By the door','Window seat','Outside','Bar'],correct:1},{question:'What do they order first?',options:['Coffee','Tea','Beer','Water'],correct:1}] },
        { id: 'lq893', type: 'dialogue', difficulty: 'hard', title: '天气', meaning: 'The Weather', turns: [{speaker:'A',chinese:'今天天气真好！',pinyin:'jīntiān tiānqì zhēn hǎo!',meaning:'The weather is really nice today!'},{speaker:'B',chinese:'是啊，不冷也不热。',pinyin:'shì a, bù lěng yě bú rè.',meaning:'Yes, not cold and not hot.'},{speaker:'A',chinese:'明天会下雨吗？',pinyin:'míngtiān huì xiàyǔ ma?',meaning:'Will it rain tomorrow?'},{speaker:'B',chinese:'不会，明天也是晴天。',pinyin:'bùhuì, míngtiān yě shì qíngtiān.',meaning:'No, tomorrow will also be sunny.'},{speaker:'A',chinese:'那太好了，我们明天可以去爬山。',pinyin:'nà tài hǎo le, wǒmen míngtiān kěyǐ qù páshān.',meaning:'That’s great! We can go hiking tomorrow.'}], questions: [{question:'What is the weather like today?',options:['Rainy','Nice','Cold','Hot'],correct:1},{question:'What will tomorrow’s weather be?',options:['Rainy','Snowy','Sunny','Cloudy'],correct:2}] },
        { id: 'lq894', type: 'dialogue', difficulty: 'hard', title: '问路', meaning: 'Asking Directions', turns: [{speaker:'A',chinese:'请问，地铁站怎么走？',pinyin:'qǐngwèn, dìtiězhàn zěnme zǒu?',meaning:'Excuse me, how do I get to the subway station?'},{speaker:'B',chinese:'一直往前走，在第二个路口右转。',pinyin:'yìzhí wǎng qián zǒu, zài dì èr gè lùkǒu yòu zhuǎn.',meaning:'Go straight ahead, turn right at the second intersection.'},{speaker:'A',chinese:'远不远？要坐车吗？',pinyin:'yuǎn bù yuǎn? yào zuò chē ma?',meaning:'Is it far? Do I need to take a bus?'},{speaker:'B',chinese:'不远，走路大概十分钟就到。',pinyin:'bù yuǎn, zǒulù dàgài shí fēnzhōng jiù dào.',meaning:'Not far, about ten minutes walking.'},{speaker:'A',chinese:'好的，谢谢你！',pinyin:'hǎo de, xièxiè nǐ!',meaning:'OK, thank you!'}], questions: [{question:'Where does the person want to go?',options:['Bus stop','Subway station','Train station','Airport'],correct:1},{question:'How far is it?',options:['5 min','10 min','20 min','30 min'],correct:1}] },
        { id: 'lq895', type: 'dialogue', difficulty: 'hard', title: '买东西', meaning: 'Shopping', turns: [{speaker:'A',chinese:'这件衣服多少钱？',pinyin:'zhè jiàn yīfu duōshao qián?',meaning:'How much is this clothing?'},{speaker:'B',chinese:'两百块。质量很好，纯棉的。',pinyin:'liǎng bǎi kuài. zhìliàng hěn hǎo, chúnmián de.',meaning:'200 yuan. Good quality, pure cotton.'},{speaker:'A',chinese:'太贵了，能便宜一点吗？',pinyin:'tài guì le, néng piányi yìdiǎn ma?',meaning:'Too expensive, can you make it cheaper?'},{speaker:'B',chinese:'那您出多少钱？',pinyin:'nà nín chū duōshao qián?',meaning:'How much would you pay?'},{speaker:'A',chinese:'一百五，可以吗？',pinyin:'yì bǎi wǔ, kěyǐ ma?',meaning:'150 yuan, is that OK?'},{speaker:'B',chinese:'好吧，卖给你了。',pinyin:'hǎo ba, mài gěi nǐ le.',meaning:'Alright, sold to you.'}], questions: [{question:'What was the original price?',options:['100','150','200','250'],correct:2},{question:'What price did they agree on?',options:['100','150','200','180'],correct:1}] },
        { id: 'lq896', type: 'dialogue', difficulty: 'hard', title: '看医生', meaning: 'Seeing a Doctor', turns: [{speaker:'A',chinese:'你怎么了？哪里不舒服？',pinyin:'nǐ zěnme le? nǎlǐ bù shūfu?',meaning:'What’s wrong? Where do you feel uncomfortable?'},{speaker:'B',chinese:'医生，我头疼，还咳嗽。',pinyin:'yīshēng, wǒ tóuténg, hái késou.',meaning:'Doctor, I have a headache and cough.'},{speaker:'A',chinese:'什么时候开始的？',pinyin:'shénme shíhou kāishǐ de?',meaning:'When did it start?'},{speaker:'B',chinese:'昨天下午开始的。',pinyin:'zuótiān xiàwǔ kāishǐ de.',meaning:'Started yesterday afternoon.'},{speaker:'A',chinese:'量一下体温...三十八度，有点发烧。我给你开点药，多喝水，多休息。',pinyin:'liáng yíxià tǐwēn... sānshíbā dù, yǒudiǎn fāshāo. wǒ gěi nǐ kāi diǎn yào, duō hēshuǐ, duō xiūxi.',meaning:'Let me take temperature... 38 degrees, slight fever. I’ll prescribe medicine. Drink water and rest.'}], questions: [{question:'What symptoms?',options:['Stomachache','Headache and cough','Back pain','Sore throat'],correct:1},{question:'What was the temperature?',options:['37','38','39','40'],correct:1}] },
        { id: 'lq897', type: 'dialogue', difficulty: 'hard', title: '打电话', meaning: 'Making a Phone Call', turns: [{speaker:'A',chinese:'喂，你好！请问小王在吗？',pinyin:'wèi, nǐ hǎo! qǐngwèn Xiǎo Wáng zài ma?',meaning:'Hello! Is Xiao Wang there?'},{speaker:'B',chinese:'他现在不在。有什么事我可以转告吗？',pinyin:'tā xiànzài bú zài. yǒu shénme shì wǒ kěyǐ zhuǎngào ma?',meaning:'He’s not here now. Can I pass along a message?'},{speaker:'A',chinese:'麻烦你告诉他明天开会改到下午三点。',pinyin:'máfan nǐ gàosu tā míngtiān kāihuì gǎi dào xiàwǔ sān diǎn.',meaning:'Please tell him the meeting is changed to 3 PM tomorrow.'},{speaker:'B',chinese:'好的，我一定转告他。',pinyin:'hǎo de, wǒ yìdìng zhuǎngào tā.',meaning:'OK, I will definitely tell him.'}], questions: [{question:'Who did A call for?',options:['Xiao Li','Xiao Wang','Xiao Zhang','The boss'],correct:1},{question:'What is the message?',options:['Meeting canceled','Meeting at 3 PM','Meeting moved','Call back'],correct:1}] },
        { id: 'lq898', type: 'dialogue', difficulty: 'hard', title: '在火车站', meaning: 'At the Train Station', turns: [{speaker:'A',chinese:'你好，我要一张去上海的车票。',pinyin:'nǐ hǎo, wǒ yào yì zhāng qù Shànghǎi de chēpiào.',meaning:'Hello, I want a train ticket to Shanghai.'},{speaker:'B',chinese:'要什么时候的？',pinyin:'yào shénme shíhou de?',meaning:'For when?'},{speaker:'A',chinese:'明天上午的，有没有高铁？',pinyin:'míngtiān shàngwǔ de, yǒu méiyǒu gāotiě?',meaning:'Tomorrow morning. Is there a high-speed train?'},{speaker:'B',chinese:'有，八点有一趟。二等座三百五十块。',pinyin:'yǒu, bā diǎn yǒu yí tàng. èr děng zuò sānbǎi wǔshí kuài.',meaning:'Yes, one at 8 AM. Second class is 350 yuan.'},{speaker:'A',chinese:'好的，就这个吧。',pinyin:'hǎo de, jiù zhège ba.',meaning:'OK, I’ll take this one.'}], questions: [{question:'Where is the person going?',options:['Beijing','Shanghai','Guangzhou','Hangzhou'],correct:1},{question:'What type of train?',options:['Regular','High-speed','Sleeper','Subway'],correct:1}] },
        { id: 'lq899', type: 'dialogue', difficulty: 'hard', title: '在邮局', meaning: 'At the Post Office', turns: [{speaker:'A',chinese:'你好，我要寄一个包裹到北京。',pinyin:'nǐ hǎo, wǒ yào jì yí gè bāoguǒ dào Běijīng.',meaning:'Hello, I want to mail a package to Beijing.'},{speaker:'B',chinese:'里面是什么？',pinyin:'lǐmiàn shì shénme?',meaning:'What is inside?'},{speaker:'A',chinese:'一些书和衣服。',pinyin:'yìxiē shū hé yīfu.',meaning:'Some books and clothes.'},{speaker:'B',chinese:'请填一下这个单子。',pinyin:'qǐng tián yíxià zhège dānzi.',meaning:'Please fill out this form.'},{speaker:'A',chinese:'大概几天能到？',pinyin:'dàgài jǐ tiān néng dào?',meaning:'About how many days to arrive?'},{speaker:'B',chinese:'大概三到五天吧。',pinyin:'dàgài sān dào wǔ tiān ba.',meaning:'About 3 to 5 days.'}], questions: [{question:'What is being mailed?',options:['A letter','A package','Money','Documents'],correct:1},{question:'How long for delivery?',options:['1-2 days','3-5 days','1 week','2 weeks'],correct:1}] },
        { id: 'lq900', type: 'dialogue', difficulty: 'hard', title: '在宾馆', meaning: 'At a Hotel', turns: [{speaker:'A',chinese:'你好，我想订一个房间。',pinyin:'nǐ hǎo, wǒ xiǎng dìng yí gè fángjiān.',meaning:'Hello, I want to book a room.'},{speaker:'B',chinese:'单人间还是标准间？',pinyin:'dānrénjiān háishì biāozhǔnjiān?',meaning:'Single room or standard room?'},{speaker:'A',chinese:'单人间就行。一晚多少钱？',pinyin:'dānrénjiān jiù xíng. yì wǎn duōshao qián?',meaning:'Single room is fine. How much per night?'},{speaker:'B',chinese:'三百块一晚，含早餐。',pinyin:'sānbǎi kuài yì wǎn, hán zǎocān.',meaning:'300 yuan per night, includes breakfast.'},{speaker:'A',chinese:'好的，我住两晚。',pinyin:'hǎo de, wǒ zhù liǎng wǎn.',meaning:'OK, I’ll stay two nights.'}], questions: [{question:'What type of room was chosen?',options:['Double','Single','Suite','Standard'],correct:1},{question:'Does the price include breakfast?',options:['No','Yes','Depends','Not mentioned'],correct:1}] }
